Can't you:
```
def _wrap_linked_callable(callable):
    @wraps(callable)
    def wrapped_callable(greenlet):
        try:
            callable(greenlet)
        except gevent.get_hub().SYSTEM_ERROR:
            raise
        except Exception as exception:
            raise UnhandledExceptionInGreenlet(exception) from exception
    return wrapped_callable

def patch_link_method(cls, method_name):
    unsafe = getattr(cls, method_name)
    def safe_link(self, callable):
        return unsafe(self, _wraps_linked_callable(callable))
    setattr(cls, method_name, safe_link)

patch_link_method(gevent.event.AsyncResult, 'link')
patch_link_method(gevent.event.AsyncResult, 'link_exception')
...
```
? That should work for Greenlet and friends too
